import React, { useRef, useEffect, useCallback } from 'react';
import { WF_NODES, WF_EDGES } from '../data';
import './LiveWorkflow.css';

const NODE_W    = 170;
const NODE_H    = 56;
const ORB_COUNT = 10;
const ORB_SPEED = 1.5; // px per frame — same for every orb

const ORB_COLORS = [
  '#e8571a','#a78bfa','#4ade80','#60a5fa',
  '#fbbf24','#f472b6','#2dd4bf','#f97316',
  '#c084fc','#34d399',
];

// ─── Hardcoded linear chain through the graph ─────────────────────────────────
const CHAIN = [
  'n0','n1','n2','n3','n4','n5','n6',
  'n8','n10','n11',
  'n12','n13','n14','n15','n16','n17',
];

// ─── Get the visual exit/entry points for each edge ──────────────────────────
// Vertical edge (dy > dx): exit bottom-center → entry top-center
// Horizontal edge: exit right-center → entry left-center
function edgeEndpoints(aId, bId) {
  const A = WF_NODES.find(n => n.id === aId);
  const B = WF_NODES.find(n => n.id === bId);
  const dx = Math.abs(B.x - A.x);
  const dy = Math.abs(B.y - A.y);
  if (dy > dx) {
    return {
      fx: A.x + NODE_W / 2, fy: A.y + NODE_H,
      tx: B.x + NODE_W / 2, ty: B.y,
      isVert: true,
    };
  }
  return {
    fx: A.x + NODE_W, fy: A.y + NODE_H / 2,
    tx: B.x,          ty: B.y + NODE_H / 2,
    isVert: false,
  };
}

// ─── Build the single continuous waypoint array ───────────────────────────────
//
// The path travels through nodes (orbs pass through node interiors,
// but nodes sit on a higher z-index layer so orbs are hidden inside them).
//
// Between the end of edge[i] and the start of edge[i+1] there is a gap
// (the node interior). We fill it with a straight H and/or V bridge so
// the path is FULLY CONTINUOUS with ZERO diagonal segments.
//
function buildWaypoints() {
  const pts = [];

  function pushBridge(toX, toY) {
    const last = pts[pts.length - 1];
    if (!last) return;
    const dx = Math.abs(toX - last.x);
    const dy = Math.abs(toY - last.y);
    if (dx < 0.5 && dy < 0.5) return; // already there
    if (dy < 0.5) {
      // same Y → pure horizontal
      pts.push({ x: toX, y: toY });
    } else if (dx < 0.5) {
      // same X → pure vertical
      pts.push({ x: toX, y: toY });
    } else {
      // different both → H first then V
      pts.push({ x: toX, y: last.y });
      pts.push({ x: toX, y: toY   });
    }
  }

  for (let i = 0; i < CHAIN.length - 1; i++) {
    const { fx, fy, tx, ty, isVert } = edgeEndpoints(CHAIN[i], CHAIN[i + 1]);

    // First point ever
    if (i === 0) pts.push({ x: fx, y: fy });

    // Bridge from last pushed point to start of this edge (fx, fy)
    pushBridge(fx, fy);

    // Add the edge itself
    if (isVert || Math.abs(fy - ty) < 0.5) {
      // Straight line (vertical or horizontal)
      pts.push({ x: tx, y: ty });
    } else {
      // Orthogonal elbow: H → V → H
      const midX = fx + (tx - fx) / 2;
      pts.push({ x: midX, y: fy  });
      pts.push({ x: midX, y: ty  });
      pts.push({ x: tx,   y: ty  });
    }
  }

  return pts;
}

const WP    = buildWaypoints();
const CUM   = [0];
for (let i = 1; i < WP.length; i++) {
  CUM.push(CUM[i - 1] + Math.hypot(
    WP[i].x - WP[i - 1].x,
    WP[i].y - WP[i - 1].y,
  ));
}
const TOTAL = CUM[CUM.length - 1]; // total pixel length of path

// ─── Get {x, y} at exact distance d along the path ───────────────────────────
function posAt(d) {
  // Wrap for seamless looping
  d = ((d % TOTAL) + TOTAL) % TOTAL;

  // Binary search for the segment
  let lo = 0, hi = WP.length - 2;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (CUM[mid + 1] < d) lo = mid + 1;
    else hi = mid;
  }

  const segLen = CUM[lo + 1] - CUM[lo];
  const t      = segLen > 0 ? (d - CUM[lo]) / segLen : 0;
  return {
    x: WP[lo].x + (WP[lo + 1].x - WP[lo].x) * t,
    y: WP[lo].y + (WP[lo + 1].y - WP[lo].y) * t,
  };
}

// ─── Build SVG path strings for every WF_EDGE ─────────────────────────────────
function buildEdgePaths() {
  const map = {};
  WF_EDGES.forEach(([aId, bId]) => {
    const { fx, fy, tx, ty, isVert } = edgeEndpoints(aId, bId);
    let d;
    if (isVert) {
      d = `M${fx},${fy} V${ty}`;
    } else if (Math.abs(fy - ty) < 0.5) {
      d = `M${fx},${fy} H${tx}`;
    } else {
      const midX = fx + (tx - fx) / 2;
      d = `M${fx},${fy} H${midX} V${ty} H${tx}`;
    }
    map[`${aId}-${bId}`] = d;
  });
  return map;
}
const EDGE_PATHS = buildEdgePaths();

// ─── Component ───────────────────────────────────────────────────────────────
export default function LiveWorkflow() {
  const containerRef = useRef(null);
  const nodeLayerRef = useRef(null); // z-index 2 — nodes always on top
  const orbLayerRef  = useRef(null); // z-index 1 — orbs behind nodes
  const svgRef       = useRef(null);

  const stateRef = useRef({
    tx: 60, ty: -30, scale: 0.46,
    dragging: false,
    dragStartX: 0, dragStartY: 0,
    dragTx: 0, dragTy: 0,
    orbs: [],  // [{ el, dist }]
    raf: null,
    hoveredId: null,
  });

  const nodeElsRef = useRef({});
  const pathElsRef = useRef({});

  const applyTransform = useCallback(() => {
    const s = stateRef.current;
    const t = `translate(${s.tx}px,${s.ty}px) scale(${s.scale})`;
    if (nodeLayerRef.current) nodeLayerRef.current.style.transform = t;
    if (orbLayerRef.current)  orbLayerRef.current.style.transform  = t;
  }, []);

  useEffect(() => {
    const nodeLayer = nodeLayerRef.current;
    const orbLayer  = orbLayerRef.current;
    const svg       = svgRef.current;
    if (!nodeLayer || !orbLayer || !svg) return;

    // ── Draw edges (SVG is inside orbLayer = behind nodes) ──────────────
    Object.entries(EDGE_PATHS).forEach(([key, d]) => {
      const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
      path.setAttribute('fill',         'none');
      path.setAttribute('stroke',       'hsl(0,0%,40%)');
      path.setAttribute('stroke-width', '1.5');
      path.setAttribute('opacity',      '0.8');
      path.setAttribute('d',            d);
      path.style.transition = 'stroke 0.2s, opacity 0.2s';
      svg.appendChild(path);
      pathElsRef.current[key] = path;
    });

    // ── Draw nodes (in nodeLayer = on top of orbs) ───────────────────────
    WF_NODES.forEach(n => {
      const el = document.createElement('div');
      el.className = 'wf-node-card';
      el.style.cssText =
        `left:${n.x}px;top:${n.y}px;background:${n.bg};border-color:${n.border};`;
      el.innerHTML = `
        <span class="wf-node-emoji">${n.emoji}</span>
        <div class="wf-node-info">
          <p class="wf-node-title" style="color:${n.color}">${n.title}</p>
          <p class="wf-node-sub">${n.sub}</p>
        </div>`;
      el.addEventListener('mouseenter', () => onNodeEnter(n.id));
      el.addEventListener('mouseleave', () => onNodeLeave());
      nodeLayer.appendChild(el);
      nodeElsRef.current[n.id] = el;
    });

    applyTransform();

    // ── Create ORB_COUNT orbs — equally spaced along TOTAL path length ───
    const spacing = TOTAL / ORB_COUNT;
    for (let i = 0; i < ORB_COUNT; i++) {
      const color = ORB_COLORS[i % ORB_COLORS.length];
      const orbEl = document.createElement('div');
      orbEl.className = 'wf-orb';
      orbEl.style.cssText = `background:${color};box-shadow:0 0 8px 3px ${color};`;
      orbLayer.appendChild(orbEl);
      stateRef.current.orbs.push({
        el:   orbEl,
        dist: i * spacing, // evenly spaced, no randomness
      });
    }

    // ── RAF loop — every orb advances by exactly ORB_SPEED px/frame ─────
    const loop = () => {
      const s = stateRef.current;
      s.orbs.forEach(orb => {
        orb.dist += ORB_SPEED;
        if (orb.dist >= TOTAL) orb.dist -= TOTAL; // seamless wrap

        // Hide all orbs when hovering a node
        orb.el.style.opacity = s.hoveredId ? '0' : '1';

        const pos = posAt(orb.dist);
        orb.el.style.left = pos.x + 'px';
        orb.el.style.top  = pos.y + 'px';
      });
      stateRef.current.raf = requestAnimationFrame(loop);
    };
    stateRef.current.raf = requestAnimationFrame(loop);

    return () => cancelAnimationFrame(stateRef.current.raf);
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Hover ────────────────────────────────────────────────────────────────
  function onNodeEnter(id) {
    stateRef.current.hoveredId = id;
    const neighbours = new Set([id]);
    WF_EDGES.forEach(([a, b]) => {
      if (a === id) neighbours.add(b);
      if (b === id) neighbours.add(a);
    });
    Object.entries(nodeElsRef.current).forEach(([nid, el]) => {
      el.classList.toggle('wf-node--dimmed',      !neighbours.has(nid));
      el.classList.toggle('wf-node--highlighted',  nid === id);
    });
    Object.entries(pathElsRef.current).forEach(([key, p]) => {
      const sep  = key.indexOf('-', 1);
      const a    = key.slice(0, sep);
      const b    = key.slice(sep + 1);
      const conn = a === id || b === id;
      p.setAttribute('stroke',  conn ? 'hsl(0,0%,75%)' : 'hsl(0,0%,18%)');
      p.setAttribute('opacity', conn ? '1'              : '0.12');
    });
  }

  function onNodeLeave() {
    stateRef.current.hoveredId = null;
    Object.values(nodeElsRef.current).forEach(el =>
      el.classList.remove('wf-node--dimmed', 'wf-node--highlighted')
    );
    Object.values(pathElsRef.current).forEach(p => {
      p.setAttribute('stroke',  'hsl(0,0%,40%)');
      p.setAttribute('opacity', '0.8');
    });
  }

  // ── Pan ──────────────────────────────────────────────────────────────────
  const onMouseDown = useCallback((e) => {
    if (e.target.closest('.wf-zoom-btn')) return;
    const s = stateRef.current;
    s.dragging   = true;
    s.dragStartX = e.clientX;
    s.dragStartY = e.clientY;
    s.dragTx     = s.tx;
    s.dragTy     = s.ty;
    containerRef.current.style.cursor = 'grabbing';
    e.preventDefault();
  }, []);

  useEffect(() => {
    const onMove = (e) => {
      const s = stateRef.current;
      if (!s.dragging) return;
      s.tx = s.dragTx + (e.clientX - s.dragStartX);
      s.ty = s.dragTy + (e.clientY - s.dragStartY);
      applyTransform();
    };
    const onUp = () => {
      stateRef.current.dragging = false;
      if (containerRef.current) containerRef.current.style.cursor = 'grab';
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup',   onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup',   onUp);
    };
  }, [applyTransform]);

  // ── Zoom ─────────────────────────────────────────────────────────────────
  const onWheel = useCallback((e) => {
    e.preventDefault();
    const s    = stateRef.current;
    const rect = containerRef.current.getBoundingClientRect();
    const mx   = e.clientX - rect.left;
    const my   = e.clientY - rect.top;
    const delta    = e.deltaY > 0 ? 0.9 : 1.1;
    const newScale = Math.max(0.15, Math.min(3, s.scale * delta));
    s.tx    = mx - (mx - s.tx) * (newScale / s.scale);
    s.ty    = my - (my - s.ty) * (newScale / s.scale);
    s.scale = newScale;
    applyTransform();
  }, [applyTransform]);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', onWheel, { passive: false });
    return () => el.removeEventListener('wheel', onWheel);
  }, [onWheel]);

  const zoom = (dir) => {
    const s = stateRef.current;
    s.scale = Math.max(0.15, Math.min(3, s.scale * (dir > 0 ? 1.2 : 0.8)));
    applyTransform();
  };
  const reset = () => {
    const s = stateRef.current;
    s.tx = 60; s.ty = -30; s.scale = 0.46;
    applyTransform();
  };

  // ── Render ───────────────────────────────────────────────────────────────
  return (
    <div className="live-workflow" ref={containerRef} onMouseDown={onMouseDown}>

      <svg className="wf-grid" aria-hidden="true">
        <defs>
          <pattern id="wfgrid" width="30" height="30" patternUnits="userSpaceOnUse">
            <path d="M 30 0 L 0 0 0 30" fill="none" stroke="currentColor" strokeWidth="0.5"/>
          </pattern>
        </defs>
        <rect width="100%" height="100%" fill="url(#wfgrid)" />
      </svg>

      <div className="wf-label">
        <span>Live Workflow</span>
        <span className="wf-live-dot" aria-hidden="true" />
      </div>

      <div className="wf-zoom-controls">
        <button className="wf-zoom-btn" onClick={() => zoom(1)}  aria-label="Zoom in">+</button>
        <button className="wf-zoom-btn" onClick={() => zoom(-1)} aria-label="Zoom out">−</button>
        <button className="wf-zoom-btn wf-zoom-btn--reset" onClick={reset} aria-label="Reset view">⟳</button>
      </div>

      <div className="wf-canvas-wrap">

        {/* LAYER 1 — SVG edges + orb divs — BEHIND nodes */}
        <div className="wf-transform-layer wf-orb-layer" ref={orbLayerRef}>
          <svg
            ref={svgRef}
            width="2000" height="2000"
            style={{ position:'absolute', top:0, left:0, overflow:'visible', pointerEvents:'none' }}
          />
        </div>

        {/* LAYER 2 — node cards — ALWAYS ON TOP */}
        <div className="wf-transform-layer wf-node-layer" ref={nodeLayerRef} />

      </div>
    </div>
  );
}
